patch:
Index: backend/templates/index.html
===================================================================
--- backend/templates/index.html	
+++ backend/templates/index.html	
@@ -1,41 +1,723 @@
 <!DOCTYPE html>
 <html lang="pt-BR">
 <head>
     <meta charset="UTF-8">
     <meta name="viewport" content="width=device-width, initial-scale=1.0">
-    <title>Download - Instalador</title>
+    <title>Instalador - CyberPanel</title>
+    <link href="https://fonts.googleapis.com/css2?family=Orbitron:wght@400;700;900&family=Rajdhani:wght@300;400;500;600;700&family=Share+Tech+Mono&display=swap" rel="stylesheet">
     <style>
         * { margin: 0; padding: 0; box-sizing: border-box; }
-        body { font-family: 'Segoe UI', sans-serif; background: #0f0f1a; color: #e0e0e0; min-height: 100vh; display: flex; align-items: center; justify-content: center; }
-        .container { max-width: 600px; width: 90%; padding: 40px; }
-        h1 { font-size: 2rem; margin-bottom: 10px; color: #fff; }
-        .subtitle { color: #888; margin-bottom: 30px; }
-        .file-list { list-style: none; }
-        .file-item { background: #1a1a2e; border: 1px solid #2a2a4a; border-radius: 8px; padding: 16px 20px; margin-bottom: 10px; display: flex; align-items: center; justify-content: space-between; transition: border-color 0.2s; }
-        .file-item:hover { border-color: #4a6cf7; }
-        .file-name { font-size: 1rem; }
-        .file-icon { margin-right: 12px; color: #4a6cf7; font-size: 1.4rem; }
-        .download-btn { background: #4a6cf7; color: #fff; border: none; padding: 8px 20px; border-radius: 6px; cursor: pointer; text-decoration: none; font-size: 0.9rem; transition: background 0.2s; }
-        .download-btn:hover { background: #3a5ce5; }
-        .empty { color: #666; text-align: center; padding: 40px; }
+
+        :root {
+            --neon-pink: #ff00ff;
+            --neon-cyan: #00ffff;
+            --neon-blue: #4a6cf7;
+            --neon-purple: #8b5cf6;
+            --dark-bg: #0a0a0f;
+            --card-bg: rgba(10, 10, 20, 0.85);
+        }
+
+        body {
+            font-family: 'Rajdhani', sans-serif;
+            background: var(--dark-bg);
+            color: #e0e0e0;
+            min-height: 100vh;
+            overflow-x: hidden;
+            position: relative;
+        }
+
+        /* ===== CYBER BACKGROUND ===== */
+        .cyber-bg {
+            position: fixed;
+            top: 0; left: 0;
+            width: 100%; height: 100%;
+            z-index: -2;
+            background:
+                radial-gradient(ellipse at 20% 50%, rgba(139, 92, 246, 0.15) 0%, transparent 50%),
+                radial-gradient(ellipse at 80% 20%, rgba(255, 0, 255, 0.1) 0%, transparent 50%),
+                radial-gradient(ellipse at 50% 80%, rgba(0, 255, 255, 0.08) 0%, transparent 50%),
+                linear-gradient(180deg, #0a0a0f 0%, #0d0d1a 50%, #0a0a0f 100%);
+        }
+
+        .grid-overlay {
+            position: fixed;
+            top: 0; left: 0;
+            width: 100%; height: 100%;
+            z-index: -1;
+            background-image:
+                linear-gradient(rgba(0, 255, 255, 0.03) 1px, transparent 1px),
+                linear-gradient(90deg, rgba(0, 255, 255, 0.03) 1px, transparent 1px);
+            background-size: 50px 50px;
+            animation: gridMove 20s linear infinite;
+        }
+
+        @keyframes gridMove {
+            0% { transform: perspective(500px) rotateX(60deg) translateY(0); }
+            100% { transform: perspective(500px) rotateX(60deg) translateY(50px); }
+        }
+
+        .scanline {
+            position: fixed;
+            top: 0; left: 0;
+            width: 100%; height: 100%;
+            z-index: 100;
+            pointer-events: none;
+            background: repeating-linear-gradient(
+                0deg,
+                rgba(0, 0, 0, 0.03) 0px,
+                rgba(0, 0, 0, 0.03) 1px,
+                transparent 1px,
+                transparent 3px
+            );
+        }
+
+        .scanline::after {
+            content: '';
+            position: absolute;
+            top: 0; left: 0;
+            width: 100%; height: 4px;
+            background: linear-gradient(90deg, transparent, rgba(0, 255, 255, 0.1), transparent);
+            animation: scanline 4s linear infinite;
+        }
+
+        @keyframes scanline {
+            0% { top: -5%; }
+            100% { top: 105%; }
+        }
+
+        /* ===== FLOATING PARTICLES ===== */
+        .particles {
+            position: fixed;
+            top: 0; left: 0;
+            width: 100%; height: 100%;
+            z-index: -1;
+            overflow: hidden;
+        }
+
+        .particle {
+            position: absolute;
+            width: 2px; height: 2px;
+            background: var(--neon-cyan);
+            border-radius: 50%;
+            box-shadow: 0 0 6px var(--neon-cyan), 0 0 12px var(--neon-cyan);
+            animation: float linear infinite;
+        }
+
+        .particle:nth-child(1) { left: 10%; animation-duration: 12s; animation-delay: 0s; }
+        .particle:nth-child(2) { left: 25%; animation-duration: 15s; animation-delay: 2s; background: var(--neon-pink); box-shadow: 0 0 6px var(--neon-pink); }
+        .particle:nth-child(3) { left: 40%; animation-duration: 10s; animation-delay: 4s; }
+        .particle:nth-child(4) { left: 55%; animation-duration: 18s; animation-delay: 1s; background: var(--neon-purple); box-shadow: 0 0 6px var(--neon-purple); }
+        .particle:nth-child(5) { left: 70%; animation-duration: 14s; animation-delay: 3s; }
+        .particle:nth-child(6) { left: 85%; animation-duration: 11s; animation-delay: 5s; background: var(--neon-pink); box-shadow: 0 0 6px var(--neon-pink); }
+        .particle:nth-child(7) { left: 15%; animation-duration: 16s; animation-delay: 6s; }
+        .particle:nth-child(8) { left: 60%; animation-duration: 13s; animation-delay: 2.5s; background: var(--neon-cyan); }
+
+        @keyframes float {
+            0% { transform: translateY(110vh) scale(0); opacity: 0; }
+            10% { opacity: 1; }
+            90% { opacity: 1; }
+            100% { transform: translateY(-10vh) scale(1); opacity: 0; }
+        }
+
+        /* ===== MAIN CONTAINER ===== */
+        .container {
+            max-width: 700px;
+            width: 92%;
+            margin: 0 auto;
+            padding: 30px 20px;
+            position: relative;
+            z-index: 10;
+        }
+
+        /* ===== HEADER ===== */
+        .header {
+            text-align: center;
+            margin-bottom: 40px;
+            padding: 40px 20px 30px;
+            position: relative;
+        }
+
+        .header::before {
+            content: 'SYSTEM ONLINE';
+            position: absolute;
+            top: 10px;
+            right: 10px;
+            font-family: 'Share Tech Mono', monospace;
+            font-size: 0.65rem;
+            color: var(--neon-cyan);
+            opacity: 0.5;
+            letter-spacing: 2px;
+        }
+
+        .logo-icon {
+            font-size: 3rem;
+            margin-bottom: 15px;
+            display: block;
+            animation: pulse 2s ease-in-out infinite;
+        }
+
+        @keyframes pulse {
+            0%, 100% { filter: drop-shadow(0 0 8px var(--neon-cyan)); }
+            50% { filter: drop-shadow(0 0 20px var(--neon-cyan)) drop-shadow(0 0 40px var(--neon-purple)); }
+        }
+
+        .glitch-wrapper {
+            position: relative;
+            display: inline-block;
+        }
+
+        h1 {
+            font-family: 'Orbitron', sans-serif;
+            font-size: 2.2rem;
+            font-weight: 900;
+            color: #fff;
+            text-transform: uppercase;
+            letter-spacing: 4px;
+            position: relative;
+            text-shadow: 0 0 10px var(--neon-cyan), 0 0 20px var(--neon-cyan), 0 0 40px var(--neon-purple);
+            animation: glitch 3s infinite;
+        }
+
+        @keyframes glitch {
+            0%, 92%, 100% { transform: none; opacity: 1; }
+            93% { transform: translate(-2px, 1px) skewX(-1deg); }
+            94% { transform: translate(2px, -1px) skewX(1deg); }
+            95% { transform: translate(-1px, 2px); }
+            96% { transform: none; }
+        }
+
+        h1::before, h1::after {
+            content: attr(data-text);
+            position: absolute;
+            top: 0; left: 0;
+            width: 100%; height: 100%;
+        }
+
+        h1::before {
+            color: var(--neon-pink);
+            animation: glitchTop 3s infinite;
+            clip-path: inset(0 0 50% 0);
+        }
+
+        h1::after {
+            color: var(--neon-cyan);
+            animation: glitchBottom 3s infinite;
+            clip-path: inset(50% 0 0 0);
+        }
+
+        @keyframes glitchTop {
+            0%, 92%, 100% { transform: none; }
+            93% { transform: translate(3px, -1px); }
+            95% { transform: translate(-2px, 1px); }
+        }
+
+        @keyframes glitchBottom {
+            0%, 92%, 100% { transform: none; }
+            94% { transform: translate(-3px, 1px); }
+            96% { transform: translate(2px, -1px); }
+        }
+
+        .subtitle {
+            font-family: 'Share Tech Mono', monospace;
+            font-size: 0.85rem;
+            color: var(--neon-cyan);
+            margin-top: 15px;
+            letter-spacing: 3px;
+            text-transform: uppercase;
+            opacity: 0.7;
+        }
+
+        .subtitle::before {
+            content: '> ';
+            color: var(--neon-pink);
+        }
+
+        .line-accent {
+            width: 120px;
+            height: 2px;
+            margin: 20px auto 0;
+            background: linear-gradient(90deg, transparent, var(--neon-cyan), var(--neon-purple), var(--neon-pink), transparent);
+            position: relative;
+        }
+
+        .line-accent::after {
+            content: '';
+            position: absolute;
+            top: -3px; left: 50%;
+            transform: translateX(-50%);
+            width: 8px; height: 8px;
+            background: var(--neon-cyan);
+            border-radius: 50%;
+            box-shadow: 0 0 10px var(--neon-cyan);
+            animation: dotPulse 2s ease-in-out infinite;
+        }
+
+        @keyframes dotPulse {
+            0%, 100% { transform: translateX(-50%) scale(1); }
+            50% { transform: translateX(-50%) scale(1.5); }
+        }
+
+        /* ===== STATUS BAR ===== */
+        .status-bar {
+            display: flex;
+            justify-content: space-between;
+            align-items: center;
+            padding: 10px 20px;
+            margin-bottom: 30px;
+            background: var(--card-bg);
+            border: 1px solid rgba(0, 255, 255, 0.1);
+            border-radius: 6px;
+            font-family: 'Share Tech Mono', monospace;
+            font-size: 0.7rem;
+            color: var(--neon-cyan);
+            letter-spacing: 1px;
+        }
+
+        .status-dot {
+            display: inline-block;
+            width: 6px; height: 6px;
+            background: #00ff88;
+            border-radius: 50%;
+            margin-right: 6px;
+            box-shadow: 0 0 6px #00ff88;
+            animation: blink 2s infinite;
+        }
+
+        @keyframes blink {
+            0%, 100% { opacity: 1; }
+            50% { opacity: 0.3; }
+        }
+
+        /* ===== FILE CARDS ===== */
+        .file-list {
+            list-style: none;
+            display: flex;
+            flex-direction: column;
+            gap: 16px;
+        }
+
+        .file-card {
+            background: var(--card-bg);
+            border: 1px solid rgba(139, 92, 246, 0.2);
+            border-radius: 12px;
+            padding: 24px;
+            position: relative;
+            overflow: hidden;
+            transition: all 0.3s ease;
+            backdrop-filter: blur(10px);
+        }
+
+        .file-card::before {
+            content: '';
+            position: absolute;
+            top: 0; left: 0;
+            width: 100%; height: 100%;
+            background: linear-gradient(135deg, rgba(0, 255, 255, 0.03) 0%, transparent 50%, rgba(255, 0, 255, 0.03) 100%);
+            pointer-events: none;
+        }
+
+        .file-card::after {
+            content: '';
+            position: absolute;
+            top: 0; left: -100%;
+            width: 100%; height: 2px;
+            background: linear-gradient(90deg, transparent, var(--neon-cyan), var(--neon-pink), transparent);
+            transition: left 0.5s ease;
+        }
+
+        .file-card:hover {
+            border-color: var(--neon-purple);
+            transform: translateY(-2px);
+            box-shadow:
+                0 8px 32px rgba(139, 92, 246, 0.15),
+                0 0 0 1px rgba(139, 92, 246, 0.1),
+                inset 0 0 30px rgba(0, 255, 255, 0.02);
+        }
+
+        .file-card:hover::after {
+            left: 100%;
+        }
+
+        .card-top {
+            display: flex;
+            align-items: center;
+            gap: 14px;
+            margin-bottom: 12px;
+        }
+
+        .card-icon {
+            width: 48px; height: 48px;
+            display: flex;
+            align-items: center;
+            justify-content: center;
+            background: linear-gradient(135deg, rgba(74, 108, 247, 0.2), rgba(139, 92, 246, 0.2));
+            border: 1px solid rgba(74, 108, 247, 0.3);
+            border-radius: 10px;
+            font-size: 1.4rem;
+            flex-shrink: 0;
+        }
+
+        .card-info {
+            flex: 1;
+            min-width: 0;
+        }
+
+        .file-name {
+            font-family: 'Orbitron', sans-serif;
+            font-size: 0.95rem;
+            font-weight: 600;
+            color: #fff;
+            white-space: nowrap;
+            overflow: hidden;
+            text-overflow: ellipsis;
+        }
+
+        .file-meta {
+            display: flex;
+            gap: 16px;
+            margin-top: 4px;
+        }
+
+        .meta-tag {
+            font-family: 'Share Tech Mono', monospace;
+            font-size: 0.65rem;
+            color: var(--neon-cyan);
+            opacity: 0.6;
+            text-transform: uppercase;
+            letter-spacing: 1px;
+        }
+
+        .meta-tag::before {
+            content: '//';
+            color: var(--neon-pink);
+            margin-right: 4px;
+        }
+
+        .card-bottom {
+            display: flex;
+            align-items: center;
+            justify-content: space-between;
+            margin-top: 16px;
+            padding-top: 16px;
+            border-top: 1px solid rgba(139, 92, 246, 0.1);
+        }
+
+        .card-stats {
+            display: flex;
+            gap: 20px;
+        }
+
+        .stat {
+            text-align: center;
+        }
+
+        .stat-value {
+            font-family: 'Orbitron', sans-serif;
+            font-size: 0.9rem;
+            font-weight: 700;
+            color: var(--neon-purple);
+        }
+
+        .stat-label {
+            font-family: 'Share Tech Mono', monospace;
+            font-size: 0.55rem;
+            color: rgba(255, 255, 255, 0.4);
+            text-transform: uppercase;
+            letter-spacing: 1px;
+        }
+
+        .download-btn {
+            display: inline-flex;
+            align-items: center;
+            gap: 8px;
+            background: transparent;
+            color: var(--neon-cyan);
+            border: 1px solid var(--neon-cyan);
+            padding: 10px 24px;
+            border-radius: 6px;
+            cursor: pointer;
+            text-decoration: none;
+            font-family: 'Orbitron', sans-serif;
+            font-size: 0.75rem;
+            font-weight: 700;
+            text-transform: uppercase;
+            letter-spacing: 2px;
+            transition: all 0.3s ease;
+            position: relative;
+            overflow: hidden;
+        }
+
+        .download-btn::before {
+            content: '';
+            position: absolute;
+            top: 0; left: -100%;
+            width: 100%; height: 100%;
+            background: linear-gradient(90deg, transparent, rgba(0, 255, 255, 0.1), transparent);
+            transition: left 0.5s ease;
+        }
+
+        .download-btn:hover {
+            background: rgba(0, 255, 255, 0.1);
+            box-shadow: 0 0 20px rgba(0, 255, 255, 0.2), inset 0 0 20px rgba(0, 255, 255, 0.05);
+            transform: scale(1.02);
+        }
+
+        .download-btn:hover::before {
+            left: 100%;
+        }
+
+        .download-btn:active {
+            transform: scale(0.98);
+        }
+
+        .btn-arrow {
+            transition: transform 0.3s ease;
+        }
+
+        .download-btn:hover .btn-arrow {
+            transform: translateX(4px);
+        }
+
+        /* ===== EMPTY STATE ===== */
+        .empty-state {
+            text-align: center;
+            padding: 60px 20px;
+            background: var(--card-bg);
+            border: 1px dashed rgba(139, 92, 246, 0.3);
+            border-radius: 12px;
+            backdrop-filter: blur(10px);
+        }
+
+        .empty-icon {
+            font-size: 3rem;
+            margin-bottom: 20px;
+            opacity: 0.5;
+        }
+
+        .empty-text {
+            font-family: 'Share Tech Mono', monospace;
+            font-size: 0.9rem;
+            color: rgba(255, 255, 255, 0.4);
+            letter-spacing: 2px;
+        }
+
+        .empty-text::before {
+            content: '> ';
+            color: var(--neon-pink);
+        }
+
+        .empty-hint {
+            font-family: 'Share Tech Mono', monospace;
+            font-size: 0.7rem;
+            color: var(--neon-cyan);
+            opacity: 0.4;
+            margin-top: 10px;
+        }
+
+        /* ===== FOOTER ===== */
+        .footer {
+            text-align: center;
+            margin-top: 50px;
+            padding: 20px;
+            font-family: 'Share Tech Mono', monospace;
+            font-size: 0.65rem;
+            color: rgba(255, 255, 255, 0.2);
+            letter-spacing: 2px;
+        }
+
+        .footer-line {
+            width: 60px;
+            height: 1px;
+            margin: 0 auto 15px;
+            background: linear-gradient(90deg, transparent, rgba(139, 92, 246, 0.3), transparent);
+        }
+
+        /* ===== RESPONSIVE ===== */
+        @media (max-width: 640px) {
+            .container {
+                width: 95%;
+                padding: 20px 12px;
+            }
+
+            h1 {
+                font-size: 1.5rem;
+                letter-spacing: 2px;
+            }
+
+            .subtitle {
+                font-size: 0.7rem;
+            }
+
+            .header {
+                padding: 25px 10px 20px;
+            }
+
+            .status-bar {
+                flex-direction: column;
+                gap: 6px;
+                text-align: center;
+                padding: 12px 10px;
+            }
+
+            .file-card {
+                padding: 18px 16px;
+            }
+
+            .card-icon {
+                width: 40px; height: 40px;
+                font-size: 1.2rem;
+            }
+
+            .file-name {
+                font-size: 0.82rem;
+            }
+
+            .file-meta {
+                gap: 10px;
+                flex-wrap: wrap;
+            }
+
+            .meta-tag {
+                font-size: 0.6rem;
+            }
+
+            .card-bottom {
+                flex-direction: column;
+                gap: 16px;
+                align-items: stretch;
+            }
+
+            .card-stats {
+                justify-content: center;
+            }
+
+            .download-btn {
+                justify-content: center;
+                padding: 12px 20px;
+            }
+        }
+
+        @media (max-width: 380px) {
+            h1 {
+                font-size: 1.25rem;
+                letter-spacing: 1px;
+            }
+
+            .logo-icon {
+                font-size: 2.2rem;
+            }
+
+            .card-top {
+                flex-direction: column;
+                align-items: flex-start;
+                gap: 10px;
+            }
+
+            .card-icon {
+                width: 36px; height: 36px;
+                font-size: 1rem;
+            }
+
+            .file-name {
+                font-size: 0.78rem;
+            }
+        }
+
+        /* ===== ANIMATIONS ON LOAD ===== */
+        .fade-in {
+            opacity: 0;
+            transform: translateY(20px);
+            animation: fadeIn 0.6s ease forwards;
+        }
+
+        @keyframes fadeIn {
+            to { opacity: 1; transform: translateY(0); }
+        }
+
+        .fade-in:nth-child(1) { animation-delay: 0.1s; }
+        .fade-in:nth-child(2) { animation-delay: 0.2s; }
+        .fade-in:nth-child(3) { animation-delay: 0.3s; }
+        .fade-in:nth-child(4) { animation-delay: 0.4s; }
+        .fade-in:nth-child(5) { animation-delay: 0.5s; }
     </style>
 </head>
 <body>
+    <div class="cyber-bg"></div>
+    <div class="grid-overlay"></div>
+    <div class="scanline"></div>
+
+    <div class="particles">
+        <div class="particle"></div>
+        <div class="particle"></div>
+        <div class="particle"></div>
+        <div class="particle"></div>
+        <div class="particle"></div>
+        <div class="particle"></div>
+        <div class="particle"></div>
+        <div class="particle"></div>
+    </div>
+
     <div class="container">
-        <h1>Instalador</h1>
-        <p class="subtitle">Baixe a versao mais recente do instalador.</p>
+        <header class="header fade-in">
+            <span class="logo-icon">&#9889;</span>
+            <div class="glitch-wrapper">
+                <h1 data-text="Instalador">Instalador</h1>
+            </div>
+            <p class="subtitle">Acesse &amp; baixe a versao mais recente</p>
+            <div class="line-accent"></div>
+        </header>
+
+        <div class="status-bar fade-in">
+            <span><span class="status-dot"></span>status: online</span>
+            <span>v2.0.77</span>
+            <span>port: 5000</span>
+        </div>
+
         {% if files %}
         <ul class="file-list">
             {% for file in files %}
-            <li class="file-item">
-                <span class="file-name"><span class="file-icon">&#128196;</span>{{ file }}</span>
-                <a href="/download/{{ file }}" class="download-btn">Download</a>
+            <li class="file-card fade-in">
+                <div class="card-top">
+                    <div class="card-icon">&#128187;</div>
+                    <div class="card-info">
+                        <div class="file-name">{{ file }}</div>
+                        <div class="file-meta">
+                            <span class="meta-tag">arquivo</span>
+                            <span class="meta-tag">setup</span>
+                        </div>
